mapper.select:
SELECT t.id, t.category, t.subject, u.name AS member_name, DATE_FORMAT(t.created_at, '%Y.%m.%d %H:%i') AS created_at_str, t.status, CASE WHEN t.priority IN ('HIGH','URGENT') THEN 1 ELSE 0 END AS priority, COALESCE(u.plan, 'FREE') AS plan, DATE_FORMAT(u.created_at, '%Y.%m.%d') AS joined_at FROM support_ticket t JOIN users u ON u.id = t.user_id
WHERE t.status = #{status}
ORDER BY t.created_at DESC
